import{_ as e,o,c as t,e as r}from"./app-4259075f.js";const a="/assets/image-85acec74.png",c={},i=r('<h2 id="介绍" tabindex="-1"><a class="header-anchor" href="#介绍" aria-hidden="true">#</a> 介绍</h2><ul><li>官方文档：https://grpc.io/</li><li>中文文档：https://doc.oschina.net/grpc</li></ul><p>RPC，Remote Procedure Call，远程过程调用，一种通信协议，屏蔽分布式计算中的各种调用细节，可以像本地调用一样直接调用一个远程函数</p><p>gRPC，一个高性能，开源的 RPC 框架，使用 Protocol Buffers 作为数据结构序列化机制（序列化和反序列化性能比 JSON 和 XML 要好，且体积很小，适合网络传输）</p><p><img src="'+a+'" alt="Alt text"></p><h2 id="准备" tabindex="-1"><a class="header-anchor" href="#准备" aria-hidden="true">#</a> 准备</h2><ul><li>安装 protoc</li><li>安装 gRPC 核心库</li><li>安装 代码生产工具</li></ul><h2 id="proto-文件" tabindex="-1"><a class="header-anchor" href="#proto-文件" aria-hidden="true">#</a> proto 文件</h2><p>https://juejin.cn/post/6978474549025177608</p><h2 id="代码生产" tabindex="-1"><a class="header-anchor" href="#代码生产" aria-hidden="true">#</a> 代码生产</h2><p>生成代码：<code>protoc --go_out=. --go-grpc_out=. ./hello.proto</code></p><ul><li><code>--go_out=.</code> 表示 xx.pb.go 文件生成在当前目录下</li><li><code>--go-grpc_out=.</code> 表示 xx_grpc.pb.go 文件生产在当前目录下</li><li><code>./hell.proto</code> 表示通过当前目录下的 proto 文件生成对应的代码</li></ul>',12),l=[i];function d(h,p){return o(),t("div",null,l)}const n=e(c,[["render",d],["__file","index.html.vue"]]);export{n as default};
